const raw = $input.first().json;
const msg = raw.message || raw.callback_query?.message || {};
const from = raw.message?.from || raw.callback_query?.from || {};
const cb = raw.callback_query;

const userId = String(from.id || '');
const chatId = String(msg.chat?.id || from.id || '');
const username = from.username || '';
const firstName = from.first_name || '';

let type = 'unknown';
let text = '';
if (cb) { type = 'callback'; text = cb.data || ''; }
else if (msg.voice) { type = 'voice'; text = ''; }
else if (msg.photo) { type = 'photo'; text = msg.caption || ''; }
else if (msg.document) { type = 'document'; text = msg.caption || ''; }
else if (msg.text) { type = 'text'; text = msg.text; }

const startTs = Date.now();

return [{ json: {
  startTs,
  userId, chatId, username, firstName, type, text,
  messageId: msg.message_id || null,
  callbackQueryId: cb?.id || null,
  callbackMessageId: cb?.message?.message_id || null,
  voiceFileId: msg.voice?.file_id || null,
  voiceDurationSec: msg.voice?.duration || null,
  photoFileId: msg.photo ? msg.photo[msg.photo.length - 1].file_id : null,
  documentFileId: msg.document?.file_id || null,
  documentName: msg.document?.file_name || null,
  raw,
} }];

const msg = $('Normalize').first().json;
const users = $input.all().map((i) => i.json);
const user = users.find((u) => u.fields?.Active === true) || null;
if (!user) return [{ json: { ...msg, authorized: false } }];
return [{ json: { ...msg, authorized: true, userFields: user.fields } }];

const msg = $('Auth').first().json;
// OpenAI node returns transcription either in .text or .transcription
const out = $input.first().json;
const transcript = (out.text || out.transcription || '').trim();
return [{ json: { ...msg, text: transcript, type: 'text', fromVoice: true } }];

// Decide routing: command (handled locally) or natural (send to GPT)
let msg;
try {
  const vt = $('VoiceToText').first();
  msg = (vt && vt.json && vt.json.fromVoice) ? vt.json : $('Auth').first().json;
} catch (e) {
  msg = $('Auth').first().json;
}
const schedule = $input.first().json;
const text = (msg.text || '').trim();
const lower = text.toLowerCase();

// Commands that don't need GPT
const isStart = (lower === '/start' || lower.startsWith('/start '));
const isHelp = (lower === '/help' || lower === '/помощь');
const isGantt = (lower === '/график' || lower === '/gantt');
const isStatus = (lower === '/статус' || lower === '/status');
const isCancel = (lower === '/отмена' || lower === '/cancel');

// Unsupported types
const unsupported = (msg.type === 'photo' || msg.type === 'document');

const needsGPT = !isStart && !isHelp && !isGantt && !isStatus && !isCancel && !unsupported && text.length > 1;

return [{ json: { ...msg, schedule, needsGPT, commandType: isStart?'start':isHelp?'help':isGantt?'gantt':isStatus?'status':isCancel?'cancel':unsupported?'unsupported':null } }];

// Build OpenAI chat completion request body with structured output.
// msg is from PreClassify (through $('PreClassify'))
const msg = $('PreClassify').first().json;
const schedule = msg.schedule;

// Conversation context from FetchConversation node (last 5 AuditLog entries for this user)
const history = $input.all().map(i => i.json).filter(r => r && r.fields).map(r => r.fields);
const contextLines = history
  .slice(0, 5)
  .reverse()
  .map(h => {
    const ts = h.Timestamp ? new Date(h.Timestamp).toLocaleTimeString('ru-RU', {hour:'2-digit',minute:'2-digit'}) : '';
    const userMsg = (h.MessageText || '').slice(0, 120);
    const botResp = (h.ResultMessage || '').slice(0, 120).replace(/\n/g, ' ');
    const intent = h.Intent || '?';
    return `  [${ts}] user: "${userMsg}" → bot(${intent}): "${botResp}"`;
  })
  .join('\n');
const contextBlock = contextLines
  ? `\n\nКонтекст последних сообщений этого пользователя (для оценки непрерывности диалога):\n${contextLines}\n\nЕсли пользователь повторяет вопрос в других словах — предыдущий ответ был НЕ тот. Пересмотри интент.`
  : '';


const INTENTS = [
  { id: 'mark_complete',  desc: 'отметить задачу завершённой (готово, закончили, сделали, закрыли)' },
  { id: 'mark_started',   desc: 'отметить старт задачи (начали, стартовали, запустили, приступили)' },
  { id: 'set_progress',   desc: 'поставить процент выполнения (N%, процентов, половина, треть, почти готово)' },
  { id: 'shift_dates',    desc: 'сдвинуть сроки задачи на N дней или на конкретную дату (перенеси, сдвинь, отложи, раньше)' },
  { id: 'add_delay',      desc: 'зафиксировать задержку с причиной (задержка, стоим, ждём материал/согласование)' },
  { id: 'add_note',       desc: 'добавить текстовую заметку к задаче (заметка, запиши, примечание)' },
  { id: 'add_task',       desc: 'добавить новую задачу в график' },
  { id: 'query_status',   desc: 'общая сводка по проекту (как дела, статус, прогресс, отчёт)' },
  { id: 'query_today',    desc: 'задачи активные сегодня или завтра (что сегодня, что на завтра)' },
  { id: 'query_overdue',  desc: 'просроченные задачи (что просрочено, отставание, где тормозим)' },
  { id: 'query_period',   desc: 'задачи на период (неделя/месяц/май — конкретный промежуток)' },
  { id: 'query_section',  desc: 'прогресс по секции (как электрика, по сантехнике, стены)' },
  { id: 'greeting',       desc: 'приветствие (привет, здорово)' },
  { id: 'smalltalk',      desc: 'болталка вне темы проекта' },
  { id: 'unknown',        desc: 'не удалось понять — присвой только если ВООБЩЕ не похоже ни на одну задачу' }
];

const systemPrompt = `Ты — интент-классификатор для русского Telegram-бота по графику стройки Orange Group Office в Дубае. Извлекай структурированный JSON строго по схеме.

Возможные intent'ы:
${INTENTS.map(i => `• ${i.id} — ${i.desc}`).join('\n')}

Как работать:
1. Прочитай сообщение пользователя (оно на русском, возможно с неформальным стилем, ошибками транскрипции, размытой формулировкой).
2. Сопоставь с наиболее подходящим intent. Не бойся уверенно присваивать даже если фраза не точная — цель максимум покрытия. unknown ТОЛЬКО если это болталка вне темы проекта или оскорбления.
3. Если упомянута задача — извлеки task_query (любой фрагмент имени) и попробуй сопоставить с task_id из списка.
4. Если есть два-три равновероятных варианта → заполни suggested_intents списком из 2-4 наиболее вероятных intent'ов в порядке убывания.
5. Если уверен ≥ 0.8 — suggested_intents оставь null.

Правила полей:
• task_query — свободное описание упомянутой работы (пример: «малярка», «электрика», «стяжка»)
• task_id — строковый ID из списка задач если смог однозначно сопоставить (не гадай — лучше null)
• days — целое ±N для shift_dates/add_delay, null иначе
• value — число 0..1 для set_progress (30% = 0.3). null иначе
• date — ISO YYYY-MM-DD. Относительные («вчера»/«завтра»/«в среду») посчитай от сегодня
• reason — текст причины задержки, null иначе
• confidence — 0..1, честная оценка уверенности
• clarify_question — если confidence < 0.75 или нужна доп. информация от пользователя. На русском, с естественным тоном, без канцелярита. null если уверен.
• suggested_intents — массив 2-4 intent-id для unknown или confidence < 0.6. null если уверен.

Особые случаи:
• Вопросы как дела / как свои дела / как там / ну чё / что нового / как успехи / всё ли в порядке — ВСЕГДА query_status (спрашивают про проект). Не smalltalk, не greeting.
• Вопросы что сегодня / что сейчас идёт / чем заняты / что завтра → query_today.
• Где отстаём / что просрочено / проблемы / где тормозим → query_overdue.
• Короткие реплики без контекста (ок, да, пойдёт) — smalltalk с clarify_question.
• Приветствия привет / здорово / салам — greeting, в clarify_question предложи команды.
• Ругательства без дела — smalltalk, clarify_question=Чем помочь по проекту?
• Ты обслуживаешь ТОЛЬКО стройбота. Любое сообщение с упоминанием работ/сроков/секций — про проект, не болталка.`;

const today = new Date().toISOString().slice(0,10);
const tasksList = schedule.tasks.map(t => `[${t.id}] ${t.name} (секция: ${t.section}, план: ${t.planStart}..${t.planEnd}${t.actualEnd ? ', факт: завершена '+t.actualEnd : t.actualStart ? ', в работе с '+t.actualStart : ', не начата'})`).join('\n');
const sectionsList = schedule.sections.map(s => s.id + '=' + s.name).join(', ');
const userContent = `Сегодня: ${today}\n\nСписок задач проекта:\n${tasksList}\n\nСекции: ${sectionsList}${contextBlock}\n\nТекущее сообщение пользователя: «${msg.text}»`;

const body = {
  model: 'gpt-5',
  response_format: {
    type: 'json_schema',
    json_schema: {
      name: 'intent',
      strict: true,
      schema: {
        type: 'object',
        additionalProperties: false,
        required: ['intent','confidence','task_query','task_id','date','days','value','reason','new_name','new_section','clarify_question','suggested_intents'],
        properties: {
          intent: { type: 'string', enum: INTENTS.map(i => i.id) },
          confidence: { type: 'number' },
          task_query: { type: ['string','null'] },
          task_id: { type: ['string','null'] },
          date: { type: ['string','null'] },
          days: { type: ['number','null'] },
          value: { type: ['number','null'] },
          reason: { type: ['string','null'] },
          new_name: { type: ['string','null'] },
          new_section: { type: ['string','null'] },
          clarify_question: { type: ['string','null'] },
          suggested_intents: {
            type: ['array','null'],
            items: { type: 'string', enum: INTENTS.map(i => i.id) }
          }
        }
      }
    }
  },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userContent }
  ]
};

return [{ json: { ...msg, openaiBody: body } }];

// Merge GPT output into msg context.
const msg = $('PreClassify').first().json;
const gpt = $input.first().json;
let parsed = null;
try {
  parsed = JSON.parse(gpt.choices[0].message.content);
} catch (e) {
  parsed = { intent: 'unknown', confidence: 0, clarify_question: 'Не смог разобрать твой запрос. Переформулируй?' };
}
return [{ json: { ...msg, gpt: parsed } }];

// Build final response based on PreClassify or GPT output.
// Returns: responseText, pendingAction (null or object), useKeyboard (bool), intent.

const msg = $input.first().json;
const schedule = msg.schedule;
const name = msg.userFields?.Name || msg.firstName || 'друг';
const GANTT = 'https://cyfr-schedule-app.vercel.app/';
const TODAY = new Date();
const today = TODAY.toISOString().slice(0, 10);

function fmtDate(iso) {
  const d = new Date(iso);
  return d.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' });
}
function findTask(q) {
  if (!q) return null;
  const needle = q.toLowerCase();
  // Exact id match
  let t = schedule.tasks.find(x => x.id === q);
  if (t) return [t];
  // Substring in name
  let matches = schedule.tasks.filter(x => x.name.toLowerCase().includes(needle));
  if (matches.length) return matches;
  // Section id match → all tasks in section
  const sec = schedule.sections.find(s => s.id === needle || s.name.toLowerCase().includes(needle));
  if (sec) return schedule.tasks.filter(x => x.section === sec.id);
  return [];
}

function statusText() {
  const p = schedule.project;
  const tasks = schedule.tasks;
  const start = new Date(p.startDate);
  const end = new Date(p.endDate);
  let pctTime = 0;
  if (TODAY < start) pctTime = 0;
  else if (TODAY > end) pctTime = 100;
  else pctTime = Math.round(((TODAY - start) / (end - start)) * 100);
  const done = tasks.filter(t => t.actualEnd).length;
  const running = tasks.filter(t => t.actualStart && !t.actualEnd).length;
  const notStarted = tasks.filter(t => !t.actualStart).length;
  const overdue = tasks.filter(t => !t.actualEnd && new Date(t.planEnd || t.end) < TODAY);
  const pctTasks = Math.round((done / tasks.length) * 100);
  const overdueList = overdue.slice(0,5).map(t => {
    const dd = Math.round((TODAY - new Date(t.planEnd || t.end)) / 86400000);
    return `• _${t.name}_ — ${dd} дн.`;
  }).join('\n');
  let updLine = '';
  if (p.lastUpdated) updLine = `\n🕐 Обновлено: ${fmtDate(p.lastUpdated)}${p.lastUpdatedBy ? ' · '+p.lastUpdatedBy : ''}`;
  return `📊 *${p.name}*\n\n⏱ По времени: *${pctTime}%*\n✅ По задачам: *${pctTasks}%* (${done} из ${tasks.length})\n\n🟡 В работе: ${running}\n⚪️ Не начато: ${notStarted}\n🔴 Просрочено: ${overdue.length}${overdue.length ? '\n\n*Топ просрочек:*\n'+overdueList : ''}${updLine}\n\n🔗 ${GANTT}`;
}

function todayText() {
  const tasks = schedule.tasks.filter(t => {
    const ps = new Date(t.planStart || t.start);
    const pe = new Date(t.planEnd || t.end);
    return ps <= TODAY && TODAY <= pe;
  });
  if (!tasks.length) return `📅 На сегодня нет активных задач по плану.\n\n🔗 ${GANTT}`;
  const lines = tasks.map(t => {
    const pe = new Date(t.planEnd || t.end);
    const dd = Math.round((pe - TODAY) / 86400000);
    const st = t.actualEnd ? '✅' : t.actualStart ? '🟡' : '⚪️';
    return `${st} _${t.name}_ · до ${fmtDate(t.planEnd)} (${dd} дн.)`;
  }).join('\n');
  return `📅 *Сегодня по плану:*\n\n${lines}\n\n🔗 ${GANTT}`;
}

function overdueText() {
  const overdue = schedule.tasks.filter(t => !t.actualEnd && new Date(t.planEnd || t.end) < TODAY);
  if (!overdue.length) return `🎉 Нет просроченных задач!`;
  const lines = overdue.slice(0,10).map(t => {
    const dd = Math.round((TODAY - new Date(t.planEnd || t.end)) / 86400000);
    return `🔴 _${t.name}_ · план до ${fmtDate(t.planEnd)} · просрочено на *${dd} дн.*`;
  }).join('\n');
  return `⚠️ *Просрочено: ${overdue.length}*\n\n${lines}\n\n🔗 ${GANTT}`;
}

function sectionText(secQuery) {
  const sec = schedule.sections.find(s => s.id === secQuery || s.name.toLowerCase().includes((secQuery || '').toLowerCase()));
  if (!sec) return `🤔 Не нашёл секцию «${secQuery}». Список: ${schedule.sections.map(s=>s.name).join(', ')}.`;
  const tasks = schedule.tasks.filter(t => t.section === sec.id);
  const done = tasks.filter(t => t.actualEnd).length;
  const running = tasks.filter(t => t.actualStart && !t.actualEnd).length;
  const pct = Math.round((done / tasks.length) * 100);
  const lines = tasks.map(t => {
    const st = t.actualEnd ? '✅' : t.actualStart ? '🟡' : '⚪️';
    return `${st} [${t.id}] _${t.name}_ · ${fmtDate(t.planStart)} → ${fmtDate(t.planEnd)}`;
  }).join('\n');
  return `🎨 *${sec.name}* — ${pct}% (${done}/${tasks.length})\n\n${lines}\n\n🔗 ${GANTT}`;
}

function startText() {
  return `👋 Привет, ${name}!\n\nЯ помогаю вести график работ. Можно писать *текстом* или диктовать *голосом* — пойму.\n\n━━━━━━━━━━━━━━━\n📊 *Узнать что происходит:*\n• _«как дела»_, _«статус»_, _«что сегодня»_\n• _«что просрочено?»_, _«как электрика»_\n\n✏️ *Отметить прогресс:*\n• _«электрика готова»_\n• _«ГКЛ закончили вчера»_\n• _«малярка на 60%»_\n\n📅 *Подвинуть сроки:*\n• _«сдвинь потолки на 3 дня позже»_\n• _«старт покраски перенеси на понедельник»_\n\n⚠️ *Задержка:*\n• _«шпатлёвка стоит — ждём материал»_\n\n📸 *Файлы (скоро):*\n• PDF/Word со сметой → создам новый проект\n• Фото с объекта → прикреплю к задаче\n\n━━━━━━━━━━━━━━━\n🔗 *График онлайн:* ${GANTT}\n\n💡 *Советую закрепить это сообщение* — пригодится как справочник.`;
}

function helpText() {
  return `📋 *Как со мной разговаривать:*\n\nМожно *голосом* или *текстом* — без строгих команд. Примеры:\n\n📊 _«как дела»_ · _«статус»_ · _«что сегодня»_\n✏️ _«электрика готова»_ · _«стяжку закрыли вчера»_\n📅 _«перенеси потолки на 3 дня»_\n⚠️ _«задержка по малярке, ждём цвет»_\n\n*Явные команды:*\n• /статус — сводка проекта\n• /график — ссылка на витрину\n• /отмена — отменить текущий диалог\n\n🔗 ${GANTT}`;
}

// ─── Main logic ───
let responseText = '';
let intent = msg.commandType || 'unknown';
let pendingAction = null;
let useKeyboard = false;

if (msg.commandType === 'start') {
  responseText = startText();
} else if (msg.commandType === 'help') {
  responseText = helpText();
} else if (msg.commandType === 'gantt') {
  responseText = `🔗 Витрина графика:\n${GANTT}\n\nПлан/факт по ${schedule.tasks.length} задачам, milestone, прогресс, субподрядчики.`;
} else if (msg.commandType === 'status') {
  responseText = statusText();
} else if (msg.commandType === 'cancel') {
  responseText = `❎ Нечего отменять — активных диалогов нет.`;
} else if (msg.commandType === 'unsupported') {
  if (msg.type === 'photo') responseText = `📸 Фото — скоро. Будет привязка к задаче.`;
  else responseText = `📄 Документы — скоро. PDF/Word со сметой → создание нового проекта.`;
} else if (msg.gpt) {
  // GPT classification
  const g = msg.gpt;
  intent = g.intent;

  if (g.clarify_question) {
    const intentLabel = {
      mark_complete: '✅ отметить готовой',
      mark_started: '🟡 отметить стартом',
      set_progress: '📊 поставить %',
      shift_dates: '📅 сдвинуть сроки',
      add_delay: '⚠️ задержка',
      query_status: '📊 статус',
      query_today: '📅 сегодня',
      query_overdue: '🔴 просрочки',
      query_section: '🎨 по секции'
    };
    const sugg = (g.suggested_intents || []).filter(i => intentLabel[i]).slice(0, 4);
    const hintLines = sugg.length ? `\n\nМожет один из:\n${sugg.map(i => '• ' + intentLabel[i]).join('\n')}` : '';
    const transcriptPrefix = msg.fromVoice ? `🎤 _«${msg.text}»_\n\n` : '';
    responseText = `${transcriptPrefix}🤔 ${g.clarify_question}${hintLines}`;
    intent = 'clarify';
  } else if (g.intent === 'query_status') {
    responseText = statusText();
  } else if (g.intent === 'query_today') {
    responseText = todayText();
  } else if (g.intent === 'query_overdue') {
    responseText = overdueText();
  } else if (g.intent === 'query_section') {
    responseText = sectionText(g.task_query);
  } else if (g.intent === 'greeting') {
    responseText = `👋 Привет! Напиши _«статус»_ или диктуй что произошло.`;
  } else if (g.intent === 'mark_complete' || g.intent === 'mark_started' || g.intent === 'set_progress' || g.intent === 'shift_dates' || g.intent === 'add_delay') {
    // Write intents → resolve task, stage confirmation
    const candidates = findTask(g.task_id || g.task_query);
    if (!candidates || candidates.length === 0) {
      responseText = `🤔 Не нашёл задачу «${g.task_query || g.task_id}».\n\nПопробуй назвать точнее или /график.`;
      intent = 'task_not_found';
    } else if (candidates.length > 1) {
      const list = candidates.slice(0,5).map(t => `• [${t.id}] _${t.name}_`).join('\n');
      responseText = `🔍 Нашёл несколько задач, уточни:\n\n${list}\n\nНапиши ID (например _«закрой 3»_) или уточни название.`;
      intent = 'task_ambiguous';
    } else {
      const t = candidates[0];
      const datePart = g.date ? fmtDate(g.date) : fmtDate(today);
      let confirmText = '';
      if (g.intent === 'mark_complete') confirmText = `✅ Отметить «${t.name}» завершённой ${datePart}?`;
      else if (g.intent === 'mark_started') confirmText = `🟡 Отметить «${t.name}» стартовавшей ${datePart}?`;
      else if (g.intent === 'set_progress') confirmText = `📊 Поставить прогресс «${t.name}» = ${Math.round((g.value||0)*100)}%?`;
      else if (g.intent === 'shift_dates') confirmText = `📅 Сдвинуть «${t.name}» на ${g.days > 0 ? '+' : ''}${g.days} дней?`;
      else if (g.intent === 'add_delay') confirmText = `⚠️ Задержка по «${t.name}» ${g.days ? '(+'+g.days+' дней) ' : ''}· причина: «${g.reason || '—'}»?`;

      pendingAction = {
        type: g.intent,
        taskId: t.id,
        taskName: t.name,
        date: g.date || today,
        days: g.days,
        value: g.value,
        reason: g.reason
      };
      const transcriptPrefix = msg.fromVoice ? `🎤 _«${msg.text}»_\n\n` : '';
      responseText = `${transcriptPrefix}${confirmText}`;
      useKeyboard = true;
    }
  } else if (g.intent === 'add_task' || g.intent === 'add_note' || g.intent === 'query_period') {
    responseText = `⏳ _«${g.intent}»_ в разработке. Пока можно: отметить готово, сдвинуть, задержку.`;
    intent = 'not_implemented';
  } else {
    // unknown / smalltalk / greeting fallback — попробуем предложить варианты
    const intentLabel = {
      mark_complete: '✅ отметить готовой',
      mark_started: '🟡 отметить стартом',
      set_progress: '📊 поставить %',
      shift_dates: '📅 сдвинуть сроки',
      add_delay: '⚠️ зафиксировать задержку',
      query_status: '📊 общий статус',
      query_today: '📅 задачи на сегодня',
      query_overdue: '🔴 просроченные',
      query_section: '🎨 по секции',
    };
    const sugg = (g.suggested_intents || []).filter(i => intentLabel[i]).slice(0, 4);
    const transcriptPrefix = msg.fromVoice ? `🎤 _«${msg.text}»_\n\n` : '';
    if (sugg.length) {
      const lines = sugg.map(i => `• ${intentLabel[i]}`).join('\n');
      responseText = `${transcriptPrefix}🤔 Не уверен что именно ты хочешь. Возможно ты имел в виду:\n\n${lines}\n\nПереформулируй поточнее — или скажи _«помощь»_ чтобы увидеть все команды.`;
    } else {
      responseText = `${transcriptPrefix}🤔 Не понял. Попробуй _«статус»_, _«что просрочено»_ или _«электрика готова»_.\n\nВсе команды: /help`;
    }
    intent = 'unknown';
  }
} else {
  responseText = `🤔 Не распознал. /help`;
}

return [{ json: { ...msg, intent, responseText, pendingAction, useKeyboard } }];

// Stage pending confirmation: generate id, insert to Airtable.
const msg = $input.first().json;
const confirmId = 'c' + Math.random().toString(36).slice(2,10);
const expiresAt = new Date(Date.now() + 15*60000).toISOString();
return [{ json: {
  ...msg,
  confirmId,
  expiresAt,
  actionJson: JSON.stringify(msg.pendingAction)
} }];

// Parse callback_data: 'confirm:<id>' or 'cancel:<id>'
const msg = $('Auth').first().json;
const parts = (msg.text || '').split(':');
const action = parts[0]; // confirm or cancel
const confirmId = parts[1] || '';
return [{ json: { ...msg, cbAction: action, cbConfirmId: confirmId } }];

// Merge callback context + pending record.
const msg = $('ParseCallback').first().json;
const recs = $input.all().map(i => i.json);
if (!recs.length) {
  return [{ json: { ...msg, pendingFound: false } }];
}
const rec = recs[0];
let action = {};
try { action = JSON.parse(rec.fields?.Action || '{}'); } catch(e) {}
return [{ json: {
  ...msg,
  pendingFound: true,
  pendingRecordId: rec.id,
  pendingAction: action,
  pendingExpired: new Date(rec.fields?.ExpiresAt || 0) < new Date()
} }];
